 1	import * as React from 'react';
 2	import { ObjectCheck, ValidationTypes } from '../../types/IstioObjects';
 3	import {
 4	  DEGRADED,
 5	  hasProxyStatusInfoSeverity,
 6	  HEALTHY,
 7	  INFO,
 8	  isProxyStatusSynced,
 9	  mergeStatus,
10	  ProxyStatus,
11	  Status
12	} from '../../types/Health';
13	import { Tooltip, TooltipPosition } from '@patternfly/react-core';
14	import { ProxyStatusList } from './ProxyStatusList';
15	import { highestSeverity, validationToHealth } from '../../types/ServiceInfo';
16	import { ValidationStack } from '../../components/Validations/ValidationStack';
17	import { createIcon } from 'config/KialiIcon';
18	
19	type PodStatusProps = {
20	  checks?: ObjectCheck[];
21	  proxyStatus?: ProxyStatus;
22	};
23	
24	export const PodStatus: React.FC<PodStatusProps> = (props: PodStatusProps) => {
25	  const proxyStatusSeverity: Status =
26	    props.proxyStatus && hasProxyStatusInfoSeverity(props.proxyStatus)
27	      ? INFO
28	      : props.proxyStatus && !isProxyStatusSynced(props.proxyStatus)
29	      ? DEGRADED
30	      : HEALTHY;
31	
32	  const showTooltip = (): boolean => {
33	    const validationSeverity: ValidationTypes = highestSeverity(props.checks || []);
34	    return proxyStatusSeverity.name !== HEALTHY.name || validationSeverity !== ValidationTypes.Correct;
35	  };
36	
37	  if (showTooltip()) {
38	    const severityIcon = (): Status => {
39	      const validationSeverity: Status = validationToHealth(highestSeverity(props.checks ?? []));
40	      return mergeStatus(proxyStatusSeverity, validationSeverity);
41	    };
42	
43	    const tooltipContent: React.ReactNode = (
44	      <>
45	        <ProxyStatusList status={props.proxyStatus} />
46	        <ValidationStack checks={props.checks} />
47	      </>
48	    );
49	
50	    return (
51	      <Tooltip aria-label="Pod Status" position={TooltipPosition.auto} enableFlip={true} content={tooltipContent}>
52	        <span test-data="proxy-status">{createIcon(severityIcon())}</span>
53	      </Tooltip>
54	    );
55	  } else {
56	    return createIcon(HEALTHY);
57	  }
58	};

